/* Test driver */
public class Main {
    public static void main(String[] args) throws Exception {
        BoundedBuffer b = new BoundedBuffer(4);
        Coordinator c = new Coordinator(b);
        Consumer cons = new Consumer("C1", b, 5);
        c.addProducer(new Producer("P1", b, 5));
        c.addConsumer(cons);
        c.start();
        c.awaitCompletion(4000);
        System.out.println("CONSUMED=" + cons.getConsumed() + " SIZE=" + b.size());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) throws Exception {
        BoundedBuffer b = new BoundedBuffer(2);
        Coordinator c = new Coordinator(b);
        Consumer x = new Consumer("X", b, 4);
        Consumer y = new Consumer("Y", b, 4);
        c.addProducer(new Producer("A", b, 4));
        c.addProducer(new Producer("B", b, 4));
        c.addConsumer(x); c.addConsumer(y);
        c.start();
        c.awaitCompletion(4000);
        System.out.println("TOTAL=" + (x.getConsumed() + y.getConsumed()) + " SIZE=" + b.size());
    }
}

